UPDATE categories
SET icon_key = CASE slug WHEN 'event' THEN 'party' WHEN 'transportasi' THEN 'car' ELSE COALESCE(icon_key, 'box') END,
    sort_order = CASE WHEN sort_order = 0 THEN 999 ELSE sort_order END
WHERE deleted_at IS NULL;
